// sentry.server.config.ts
import * as Sentry from '@sentry/nextjs'
Sentry.init({
  dsn: process.env.SENTRY_DSN,
  tracesSampleRate: 0.2,
  beforeSend(e){ return scrubSupabaseAuth(e) },
  ignoreErrors: ['ResizeObserver loop','AbortError','NextRouter:cancel'],
})
// sentry.edge.config.ts → tracesSampleRate: 0.1 (cap)
// vercel.json env: SENTRY_AUTH_TOKEN, SENTRY_ORG, SENTRY_PROJECT
